CREATE TABLE sales (product TEXT, amount REAL, quantity INTEGER);
INSERT INTO sales VALUES ('Widget', 9.99, 50);
INSERT INTO sales VALUES ('Gadget', 49.99, 20);
INSERT INTO sales VALUES ('Thingamajig', 24.99, 35);

SELECT
  COUNT(*)          AS total_products,
  SUM(amount)       AS total_revenue,
  ROUND(AVG(amount), 2) AS avg_price,
  MIN(amount)       AS cheapest,
  MAX(amount)       AS priciest
FROM sales;

CREATE TABLE employees (name TEXT, dept TEXT, salary INTEGER);
INSERT INTO employees VALUES ('Alice', 'Engineering', 95000);
INSERT INTO employees VALUES ('Bob',   'Engineering', 105000);
INSERT INTO employees VALUES ('Carol', 'Marketing',   72000);
INSERT INTO employees VALUES ('Dave',  'Marketing',   68000);
INSERT INTO employees VALUES ('Eve',   'HR',          65000);

SELECT dept, COUNT(*) AS headcount, AVG(salary) AS avg_salary
FROM employees
GROUP BY dept
ORDER BY avg_salary DESC;

CREATE TABLE orders (customer TEXT, total REAL);
INSERT INTO orders VALUES ('Alice', 50);
INSERT INTO orders VALUES ('Alice', 120);
INSERT INTO orders VALUES ('Bob',   30);
INSERT INTO orders VALUES ('Carol', 200);
INSERT INTO orders VALUES ('Carol', 150);
INSERT INTO orders VALUES ('Carol', 90);

-- Customers who have spent more than $100 in total
SELECT customer, SUM(total) AS total_spent
FROM orders
GROUP BY customer
HAVING SUM(total) > 100
ORDER BY total_spent DESC;
